return ['domain'=>'brikpanel','plural-forms'=>'nplurals=2; plural=(n != 1);','language'=>'nl_NL','project-id-version'=>'BrikPanel','pot-creation-date'=>'2026-05-24T17:14:30+00:00','po-revision-date'=>'2026-05-23','x-generator'=>'Claude (BrikPanel auto-translation)','messages'=>['BrikPanel: WooCommerce Admin Dashboard Theme'=>'BrikPanel: WooCommerce Admin Dashboard-thema','Beautiful and modern Shopify-style WooCommerce admin panel & dashboard, fully free, forever.'=>'Mooi en modern WooCommerce-adminpaneel en -dashboard in Shopify-stijl, volledig gratis, voor altijd.','Brksoft'=>'Brksoft','https://brksoft.com/'=>'https://brksoft.com/','WooCommerce is not active on this site, so BrikPanel features are disabled here. Activate WooCommerce to enable BrikPanel.'=>'WooCommerce is niet actief op deze site, dus BrikPanel-functies zijn hier uitgeschakeld. Activeer WooCommerce om BrikPanel in te schakelen.','Order statusReturn Draft'=>'Retourconcept','Return Draft <span class="count">(%s)</span>'=>'Retourconcept <span class="count">(%s)</span>' . "\0" . 'Retourconcepten <span class="count">(%s)</span>','Order statusChange'=>'Wijzigen','Change <span class="count">(%s)</span>'=>'Wijziging <span class="count">(%s)</span>' . "\0" . 'Wijzigingen <span class="count">(%s)</span>','Settings'=>'Instellingen','Ad Platforms integration'=>'Advertentieplatforms-integratie','Pull daily ad spend from Google Ads and Meta Ads to calculate true ROAS and Net Profit on the dashboard. Currently in beta — turn it off below to hide the admin page and stop all background sync jobs. Your connections stay saved.'=>'Haal dagelijkse advertentie-uitgaven op van Google Ads en Meta Ads om echte ROAS en Nettowinst op het dashboard te berekenen. Momenteel in bèta — schakel het hieronder uit om de adminpagina te verbergen en alle achtergrondsynchronisaties te stoppen. Uw verbindingen blijven bewaard.','Enable Ad Platforms integration'=>'Advertentieplatforms-integratie inschakelen','When on, the Ad Platforms admin menu, daily sync, and dashboard ROAS / Net Profit cards are active. When off, the module is dormant: no menu item, no scheduled sync, no dashboard cards.'=>'Indien aan zijn het Advertentieplatforms-adminmenu, de dagelijkse synchronisatie en de ROAS / Nettowinst-kaarten op het dashboard actief. Indien uit is de module slapend: geen menu-item, geen geplande synchronisatie, geen dashboardkaarten.','Beta'=>'Bèta','ROAS'=>'ROAS','Google Ads connection was revoked for security. Please reconnect.'=>'Google Ads-verbinding is om veiligheidsredenen ingetrokken. Maak opnieuw verbinding.','Not connected to Google Ads.'=>'Niet verbonden met Google Ads.','The BrikPanel proxy returned an unverifiable response and was rejected.'=>'De BrikPanel-proxy gaf een niet-verifieerbaar antwoord en werd geweigerd.','Request to Google Ads failed after retries.'=>'Verzoek aan Google Ads mislukte na meerdere pogingen.','Meta Ads connection was revoked for security. Please reconnect.'=>'Meta Ads-verbinding is om veiligheidsredenen ingetrokken. Maak opnieuw verbinding.','Not connected to Meta Ads.'=>'Niet verbonden met Meta Ads.','Request to Meta Ads failed after retries.'=>'Verzoek aan Meta Ads mislukte na meerdere pogingen.','Permission denied.'=>'Toegang geweigerd.','Unknown platform.'=>'Onbekend platform.','This connection is not available yet — it is pending platform approval.'=>'Deze verbinding is nog niet beschikbaar — deze wacht op goedkeuring van het platform.','Could not reach the BrikPanel proxy. Please try again in a moment.'=>'Kon de BrikPanel-proxy niet bereiken. Probeer het zo meteen opnieuw.','Could not start OAuth: proxy returned an error.'=>'Kon OAuth niet starten: proxy retourneerde een fout.','Disconnected.'=>'Verbinding verbroken.','OAuth session expired. Please try connecting again.'=>'OAuth-sessie verlopen. Probeer opnieuw verbinding te maken.','Unknown platform in OAuth state.'=>'Onbekend platform in OAuth-status.','OAuth callback was for a different user. Aborted.'=>'OAuth-callback was voor een andere gebruiker. Geannuleerd.','Could not reach the BrikPanel proxy.'=>'Kon de BrikPanel-proxy niet bereiken.','OAuth redemption failed. Please try connecting again.'=>'OAuth-inwisseling mislukt. Probeer opnieuw verbinding te maken.','Could not save tokens. Please try again.'=>'Kon tokens niet opslaan. Probeer het opnieuw.','Google Ads connected.'=>'Google Ads verbonden.','Meta Ads connected.'=>'Meta Ads verbonden.','Ad Platforms'=>'Advertentieplatforms','Beta feature'=>'Bètafunctie','Connecting…'=>'Verbinden…','Disconnect this platform? Your synced spend data will be deleted.'=>'Verbinding met dit platform verbreken? Uw gesynchroniseerde uitgavendata worden verwijderd.','Syncing…'=>'Synchroniseren…','Sync queued. Refresh the page in a moment.'=>'Synchronisatie in wachtrij. Vernieuw de pagina zo meteen.','Saved.'=>'Opgeslagen.','Loading accounts…'=>'Accounts laden…','No ad accounts found for this connection.'=>'Geen advertentieaccounts gevonden voor deze verbinding.','Something went wrong. Please try again.'=>'Er is iets misgegaan. Probeer het opnieuw.','No errors logged.'=>'Geen fouten geregistreerd.','Connected'=>'Verbonden','Not connected'=>'Niet verbonden','Pick a primary account first.'=>'Kies eerst een primair account.','Manager'=>'Manager','Loading history… %1$d of %2$d 90-day chunks done'=>'Geschiedenis laden… %1$d van %2$d delen van 90 dagen voltooid','Connect this platform first.'=>'Verbind eerst dit platform.','Pick an account before saving.'=>'Kies een account voordat u opslaat.','Account saved. Loading 3 years of history in the background — refresh the page in a few minutes to see it.'=>'Account opgeslagen. 3 jaar geschiedenis wordt op de achtergrond geladen — vernieuw de pagina over een paar minuten om dit te zien.','Account saved.'=>'Account opgeslagen.','Synced %1$d row(s) across %2$d day(s).'=>'%1$d rij(en) gesynchroniseerd over %2$d dag(en).','Ad spend daily sync'=>'Dagelijkse synchronisatie advertentie-uitgaven','Pulls yesterday plus the last 7 days of spend from each connected ad platform.'=>'Haalt gisteren plus de laatste 7 dagen aan uitgaven op van elk verbonden advertentieplatform.','Ad spend backfill chunk'=>'Advertentie-uitgaven backfill-deel','One 90-day slice of the initial historical pull when an ad platform is first connected.'=>'Eén deel van 90 dagen van de initiële historische ophaaltaak wanneer een advertentieplatform voor het eerst wordt verbonden.','Not connected.'=>'Niet verbonden.','Pending Google approval'=>'Wacht op goedkeuring van Google','Google Ads needs to approve our API access before this connection can go live. It will be enabled automatically once approved — no action is needed from you.'=>'Google Ads moet onze API-toegang goedkeuren voordat deze verbinding live kan gaan. Deze wordt automatisch ingeschakeld na goedkeuring — u hoeft niets te doen.','Connect Google Ads'=>'Verbinden met Google Ads','Pending Meta approval'=>'Wacht op goedkeuring van Meta','Meta needs to review our app before this connection can go live. It will be enabled automatically once approved — no action is needed from you.'=>'Meta moet onze app beoordelen voordat deze verbinding live kan gaan. Deze wordt automatisch ingeschakeld na goedkeuring — u hoeft niets te doen.','Connect Meta Ads'=>'Verbinden met Meta Ads','Coming soon'=>'Binnenkort beschikbaar','BrikPanel will request read-only access to your Google Ads accounts. We only pull total daily spend, impressions and clicks — no campaign management.'=>'BrikPanel vraagt alleen-lezen-toegang tot uw Google Ads-accounts. Wij halen alleen de dagelijkse totale uitgaven, impressies en klikken op — geen campagnebeheer.','BrikPanel will request read-only access (ads_read) to your Meta ad accounts. We only pull total daily spend, impressions and clicks.'=>'BrikPanel vraagt alleen-lezen-toegang (ads_read) tot uw Meta-advertentieaccounts. Wij halen alleen de dagelijkse totale uitgaven, impressies en klikken op.','Connected as'=>'Verbonden als','(email not shared)'=>'(e-mail niet gedeeld)','Primary ad account'=>'Primair advertentieaccount','BrikPanel pulls spend from this one account. To switch later, choose another from the list and click Save.'=>'BrikPanel haalt uitgaven op van dit ene account. Om later te wisselen, kiest u een ander uit de lijst en klikt u op Opslaan.','Click "Load accounts" to choose…'=>'Klik op "Accounts laden" om te kiezen…','Load accounts'=>'Accounts laden','Save'=>'Opslaan','Manager (MCC) account ID — optional'=>'Manager (MCC) account-ID — optioneel','Only fill in if you access the chosen account through a Google Ads manager. Digits only, no dashes.'=>'Vul alleen in als u het gekozen account benadert via een Google Ads-manager. Alleen cijfers, geen streepjes.','Last successful sync'=>'Laatste succesvolle synchronisatie','ago'=>'geleden','(last attempt failed — check the error log)'=>'(laatste poging mislukt — controleer het foutenlogboek)','Sync now'=>'Nu synchroniseren','Re-authorize'=>'Opnieuw autoriseren','Disconnect'=>'Verbinding verbreken','Connect Google Ads and Meta Ads so BrikPanel can show real ROAS and Net Profit on the dashboard.'=>'Verbind Google Ads en Meta Ads zodat BrikPanel echte ROAS en Nettowinst op het dashboard kan tonen.','Google Ads'=>'Google Ads','Pulls daily total spend, impressions and clicks from one Google Ads account.'=>'Haalt dagelijkse totale uitgaven, impressies en klikken op van één Google Ads-account.','Meta Ads'=>'Meta Ads','Pulls daily total spend, impressions and clicks from one Meta ad account (Facebook + Instagram).'=>'Haalt dagelijkse totale uitgaven, impressies en klikken op van één Meta-advertentieaccount (Facebook + Instagram).','How it works'=>'Hoe het werkt','Connect each platform once. Tokens are encrypted on this server and never leave it.'=>'Verbind elk platform één keer. Tokens worden op deze server versleuteld en verlaten deze nooit.','On first connect, the last 3 years of daily spend are loaded in the background (90-day chunks every 30 seconds).'=>'Bij de eerste verbinding worden de laatste 3 jaar aan dagelijkse uitgaven op de achtergrond geladen (delen van 90 dagen elke 30 seconden).','After that, the last 7 days are refreshed once per day to capture late corrections.'=>'Daarna worden de laatste 7 dagen één keer per dag vernieuwd om late correcties vast te leggen.','Spend is stored in the ad account currency — the dashboard shows ad-currency totals next to your store revenue so you can compare them directly.'=>'Uitgaven worden opgeslagen in de valuta van het advertentieaccount — het dashboard toont totalen in advertentievaluta naast uw winkelomzet zodat u ze direct kunt vergelijken.','Recent errors'=>'Recente fouten','Last 50 entries from the sync log. Token values are redacted before storage.'=>'Laatste 50 vermeldingen uit het synchronisatielogboek. Tokenwaarden worden geredigeerd voor opslag.','View log'=>'Logboek bekijken','Clear log'=>'Logboek wissen','System default'=>'Systeemstandaard','Appearance'=>'Weergave','Customize how the BrikPanel admin interface looks. Changes apply to dashboard, products, orders, coupons, segments, the top bar, sidebar, and the modern login page. The rest of WordPress admin is untouched.'=>'Pas aan hoe de BrikPanel-admininterface eruitziet. Wijzigingen gelden voor dashboard, producten, bestellingen, kortingsbonnen, segmenten, de bovenbalk, zijbalk en de moderne inlogpagina. De rest van de WordPress-admin blijft ongewijzigd.','Interface font'=>'Interfacelettertype','Pick the typeface used across BrikPanel. "System default" stays on your operating system\'s native font (no external request). Other choices load a single Google Fonts stylesheet with display: swap.'=>'Kies het lettertype dat in heel BrikPanel wordt gebruikt. "Systeemstandaard" blijft het oorspronkelijke lettertype van uw besturingssysteem (geen externe aanvraag). Andere keuzes laden één Google Fonts-stylesheet met display: swap.','Accent color'=>'Accentkleur','Primary color used for buttons, focus rings, toggles, and active highlights. The BrikPanel default is a near-black gray (#303030); pick anything you like.'=>'Primaire kleur die wordt gebruikt voor knoppen, focusringen, schakelaars en actieve markeringen. De BrikPanel-standaard is een bijna zwart grijs (#303030); kies wat u maar wilt.','Custom brand logo'=>'Aangepast merklogo','Replace the BrikPanel mark in the admin top bar and on the modern login page with your own brand logo. When off, the default BrikPanel icon and your site name are shown.'=>'Vervang het BrikPanel-merkteken in de adminbovenbalk en op de moderne inlogpagina door uw eigen merklogo. Indien uit worden het standaard BrikPanel-pictogram en uw sitenaam getoond.','Brand logo image'=>'Merklogo-afbeelding','Pick or upload an image from your media library. The same logo is used in the admin top bar and on the modern login page. PNG or SVG with transparent background gives the cleanest result. Recommended size: 256×256 px or wider.'=>'Kies of upload een afbeelding uit uw mediabibliotheek. Hetzelfde logo wordt gebruikt in de adminbovenbalk en op de moderne inlogpagina. PNG of SVG met transparante achtergrond geeft het schoonste resultaat. Aanbevolen grootte: 256×256 px of breder.','No logo selected'=>'Geen logo geselecteerd','Replace logo'=>'Logo vervangen','Select logo'=>'Logo selecteren','Remove'=>'Verwijderen','Select brand logo'=>'Merklogo selecteren','Use this image'=>'Gebruik deze afbeelding','Product Image Health'=>'Productafbeeldingsgezondheid','Scanning… %1$s / %2$s products'=>'Scannen… %1$s / %2$s producten','No product images found yet.'=>'Nog geen productafbeeldingen gevonden.','%1$s%% oversized (%2$s of %3$s) · %4$s%% modern format'=>'%1$s%% te groot (%2$s van %3$s) · %4$s%% modern formaat','Add product images to start the health check.'=>'Voeg productafbeeldingen toe om de gezondheidscontrole te starten.','%1$s product images are larger than 1 MB. Modern formats (WebP / AVIF) cover %2$s%% of your library. Missing files: %3$s.'=>'%1$s productafbeeldingen zijn groter dan 1 MB. Moderne formaten (WebP / AVIF) bestrijken %2$s%% van uw bibliotheek. Ontbrekende bestanden: %3$s.','No products yet — nothing to check.'=>'Nog geen producten — niets te controleren.','Add at least one published product to enable image health checks.'=>'Voeg minstens één gepubliceerd product toe om afbeeldingsgezondheidscontroles in te schakelen.','Install %s to compress images and convert to WebP/AVIF automatically.'=>'Installeer %s om afbeeldingen automatisch te comprimeren en te converteren naar WebP/AVIF.','Install plugin'=>'Plugin installeren','%1$s product images (%2$s%%) are larger than 1 MB. These slow down your product pages and hurt SEO. Compress them to under 200 KB where possible.'=>'%1$s productafbeeldingen (%2$s%%) zijn groter dan 1 MB. Deze vertragen uw productpagina\'s en schaden SEO. Comprimeer ze waar mogelijk tot onder de 200 KB.','Only %s%% of your product images use WebP / AVIF. Modern formats are 30–50%% smaller than JPEG/PNG with no visible quality loss.'=>'Slechts %s%% van uw productafbeeldingen gebruikt WebP / AVIF. Moderne formaten zijn 30–50%% kleiner dan JPEG/PNG zonder zichtbaar kwaliteitsverlies.','%s product images point to files that no longer exist on disk. Re-upload them or detach the missing media references.'=>'%s productafbeeldingen verwijzen naar bestanden die niet meer op schijf bestaan. Upload ze opnieuw of koppel de ontbrekende mediareferenties los.','Your product images are well-optimised. Keep an eye on this metric as you upload new products.'=>'Uw productafbeeldingen zijn goed geoptimaliseerd. Houd deze metric in de gaten terwijl u nieuwe producten uploadt.','BrikControl: Full Health Scan'=>'BrikControl: Volledige gezondheidsscan','Runs every BrikControl check and writes results to the dashboard.'=>'Voert elke BrikControl-controle uit en schrijft de resultaten naar het dashboard.','BrikControl: Scan Batch'=>'BrikControl: Scanbatch','Processes a single batch of a long-running BrikControl check.'=>'Verwerkt één batch van een langlopende BrikControl-controle.','Store Health'=>'Winkelgezondheid','Rescan now'=>'Nu opnieuw scannen','Scan queued — refreshing…'=>'Scan in wachtrij — vernieuwen…','Could not start scan.'=>'Kon scan niet starten.','Not scanned yet'=>'Nog niet gescand','Scanning in background…'=>'Scannen op achtergrond…','just now'=>'zojuist','Scanning {cursor} / {total} products…'=>'{cursor} / {total} producten scannen…','All checks passing'=>'Alle controles geslaagd','Open Store Health'=>'Winkelgezondheid openen','Last scan'=>'Laatste scan','Scanning…'=>'Scannen…','%s min ago'=>'%s min geleden' . "\0" . '%s min geleden','%s h ago'=>'%s u geleden' . "\0" . '%s u geleden','%s d ago'=>'%s d geleden' . "\0" . '%s d geleden','You do not have permission to access this page.'=>'U heeft geen toestemming om deze pagina te openen.','Not scanned yet — run a scan to see results.'=>'Nog niet gescand — voer een scan uit om resultaten te zien.','%s critical store health issue'=>'%s kritiek winkelgezondheidsprobleem' . "\0" . '%s kritieke winkelgezondheidsproblemen','%s store health warning'=>'%s winkelgezondheidswaarschuwing' . "\0" . '%s winkelgezondheidswaarschuwingen','Store health: all checks passing'=>'Winkelgezondheid: alle controles geslaagd','Open full report'=>'Volledig rapport openen','Run a scan to see store health checks.'=>'Voer een scan uit om winkelgezondheidscontroles te zien.','%s critical store health issue detected'=>'%s kritiek winkelgezondheidsprobleem gedetecteerd' . "\0" . '%s kritieke winkelgezondheidsproblemen gedetecteerd','Open the BrikControl report to see what to fix and which plugins can help.'=>'Open het BrikControl-rapport om te zien wat u moet repareren en welke plugins kunnen helpen.','View report'=>'Rapport bekijken','Dismiss for 7 days'=>'Negeren voor 7 dagen','A scan is already running.'=>'Er wordt al een scan uitgevoerd.','Action Scheduler is unavailable.'=>'Action Scheduler is niet beschikbaar.','Scan queued.'